#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int *nums = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &nums[i]);
        long long ans = 0;
        int totalMasks = 1 << n;
        for (int mask = 1; mask < totalMasks; ++mask) {
            int sum = 0;
            for (int i = 0; i < n; ++i) {
                if (mask & (1 << i)) sum += nums[i];
            }
            if (sum == k) ++ans;
        }
        printf("%lld\n", ans);
        free(nums);
    }
    return 0;
}

